globalThis.__BQ = {"reabsorpsiyon":{"lise":{"kolay":[{"q":"Süzüntüdeki yararlı maddelerin kana geri alınmasına ne ad verilir?","steps":[{"t":"Süzme sonrası işlem","a":"Yararlıyı geri alma","d":"Glomerulusta süzülen sıvıda su, glikoz ve iyon gibi yararlı maddeler de bulunur. Bunların idrarla kaybedilmemesi gerekir. Bu maddeler kana geri alınır."},{"t":"İşlemin adı","a":"Geri emilim (reabsorpsiyon)","d":"Süzüntüdeki yararlı maddelerin tübüllerden kana geri alınmasına geri emilim (reabsorpsiyon) denir. Bu sayede değerli maddeler korunur. Geri emilim en çok proksimal tübülde olur."}],"ans":"Geri emilim (reabsorpsiyon)."},{"q":"Geri emilimin en yoğun gerçekleştiği nefron bölümü hangisidir?","steps":[{"t":"Geri emilim yeri","a":"İlk tübül","d":"Süzüntü tübüllerde ilerlerken yararlı maddeler farklı bölümlerde geri emilir. En çok geri emilim ilk tübülde olur. Bu bölüm geri emilim için özelleşmiştir."},{"t":"Bölümün adı","a":"Proksimal tübül","d":"Geri emilimin en yoğun olduğu yer proksimal tübüldür. Burada glikoz, aminoasit, su ve iyonların büyük kısmı kana geri alınır. Bu nedenle bu bölüm geri emilim merkezi gibidir."}],"ans":"Proksimal tübül."},{"q":"Sağlıklı bir insanda süzüntüdeki glikozun normalde tamamına yakını ne olur?","steps":[{"t":"Glikozun süzülmesi","a":"Süzüntüye geçer","d":"Glikoz küçük bir molekül olduğundan glomerulusta süzülür ve süzüntüye geçer. Ancak glikoz vücut için değerli bir besindir. Kaybedilmemesi gerekir."},{"t":"Geri emilim","a":"Tamamı geri emilir","d":"Sağlıklı kişide süzüntüdeki glikozun tamamına yakını proksimal tübülde geri emilerek kana döner. Bu yüzden normal idrarda glikoz bulunmaz. Geri emilim glikozu korur."}],"ans":"Tamamına yakını geri emilir (idrara geçmez)."},{"q":"Glikoz ve aminoasitlerin geri emiliminde kullanılan taşıma türü hangisidir?","steps":[{"t":"Geri emilim yönü","a":"Derişime karşı","d":"Glikoz ve aminoasitler bazen düşük derişimden yüksek derişime doğru taşınmalıdır. Bu, kendiliğinden olmaz. Enerji gerektirir."},{"t":"Taşıma türü","a":"Aktif taşıma","d":"Glikoz ve aminoasitlerin geri emilimi aktif taşıma ile yapılır ve ATP harcanır. Bu sayede maddeler derişim farkına karşı kana alınabilir. Aktif taşıma proksimal tübülde yoğundur."}],"ans":"Aktif taşıma."},{"q":"Geri emilimde suyun tübüllerden kana geçişi hangi olayla sağlanır?","steps":[{"t":"Suyun hareketi","a":"Su pasif geçer","d":"Su, tübüllerden kana geçerken genellikle çözünen derişimini izler. İyon ve glikoz emilince su da onları takip eder. Su için ayrı bir aktif pompa gerekmez."},{"t":"Olayın adı","a":"Ozmoz","d":"Suyun tübülden kana geçişi ozmozla, yani çözünen derişimi farkına bağlı pasif geçişle olur. Tuz ve glikoz emildikçe su da ozmozla geri emilir. Böylece su dengesi korunur."}],"ans":"Ozmoz (pasif geçiş)."},{"q":"Henle kulpu geri emilimde özellikle hangi maddelerin hareketini düzenler?","steps":[{"t":"Henle kulpunun rolü","a":"Öze inen yapı","d":"Henle kulpu öze inip geri dönen U biçimli bir yapıdır. Burada inen ve çıkan kollarda farklı madde hareketleri olur. Bu hareketler ortam derişimini ayarlar."},{"t":"Düzenlenen maddeler","a":"Su ve tuz","d":"Henle kulpu özellikle su ve tuzun (iyonların) hareketini düzenler. Bu düzenleme öz bölgesini tuz bakımından derişik yapar. Böylece idrarın yoğunlaştırılmasına zemin hazırlanır."}],"ans":"Su ve tuz (iyonlar)."},{"q":"Yaklaşık 180 litre süzüntüden günde ne kadar idrar oluşur?","steps":[{"t":"Süzüntü hacmi","a":"Çok büyük hacim","d":"Böbrekler günde yaklaşık 180 litre süzüntü üretir. Bu sıvının tamamı idrar olarak atılmaz. Çoğu geri emilir."},{"t":"İdrar miktarı","a":"1-2 litre","d":"Geri emilim sonucu 180 litre süzüntüden günde yaklaşık 1-2 litre idrar oluşur. Suyun büyük kısmı kana geri döner. Geriye az miktarda yoğun idrar kalır."}],"ans":"Yaklaşık 1-2 litre idrar."},{"q":"Geri emilim olmasaydı vücut için en büyük tehlike ne olurdu?","steps":[{"t":"Geri emilimin işlevi","a":"Su ve maddeyi korur","d":"Geri emilim, süzüntüdeki suyu, glikozu ve iyonları kana geri alır. Böylece bunların idrarla kaybı önlenir. Bu, değerli maddelerin korunmasını sağlar."},{"t":"Geri emilim olmazsa","a":"Büyük su ve madde kaybı","d":"Geri emilim olmasaydı günde 180 litreye yakın su ile glikoz ve iyonlar idrarla atılırdı. Bu, hızlı su kaybı ve değerli madde kaybına yol açardı. Vücut kuruyup dengesini yitirirdi."}],"ans":"Büyük miktarda su ve yararlı madde kaybı (susuz kalma ve denge bozukluğu)."},{"q":"Proksimal tübülde geri emilen başlıca maddeler hangileridir?","steps":[{"t":"Proksimal tübülün işi","a":"Yoğun geri emilim","d":"Proksimal tübül geri emilimin en yoğun olduğu bölümdür. Burada süzüntüdeki birçok yararlı madde kana geri alınır. Geri emilim genel ve güçlüdür."},{"t":"Emilen maddeler","a":"Glikoz, aminoasit, su, iyon","d":"Proksimal tübülde glikoz, aminoasitler, suyun büyük kısmı ve mineral iyonları geri emilir. Bu maddeler kana döner. Atıklar ise büyük ölçüde tübülde kalır."}],"ans":"Glikoz, aminoasitler, su ve mineral iyonları."},{"q":"Sağlıklı kişide idrarda glikoz bulunmaması neyle açıklanır?","steps":[{"t":"Glikozun süzülmesi","a":"Süzüntüde glikoz var","d":"Glikoz küçük olduğundan glomerulusta süzülür ve süzüntüye geçer. İlk süzüntüde glikoz bulunur. Ancak bu son idrar değildir."},{"t":"Geri emilim","a":"Glikoz geri emilir","d":"Proksimal tübülde glikozun tamamına yakını aktif taşımayla geri emilir ve kana döner. Bu nedenle son idrarda glikoz kalmaz. Sağlıklı idrarda glikoz bulunmaması böyle açıklanır."}],"ans":"Süzülen glikozun tamamı proksimal tübülde geri emildiği için."},{"q":"Geri emilim sayesinde vücut için değerli olan hangi besin korunur?","steps":[{"t":"Süzülen besinler","a":"Glikoz süzüntüde","d":"Glomerulusta süzülen sıvıda glikoz gibi değerli besinler de bulunur. Bunlar idrarla atılırsa kaybedilir. Geri emilim bu kaybı önler."},{"t":"Korunan besin","a":"Glikoz (ve aminoasit)","d":"Geri emilim sayesinde glikoz ve aminoasitler kana geri alınarak korunur. Bu maddeler enerji ve yapı için gereklidir. Böylece vücut değerli besinleri kaybetmez."}],"ans":"Glikoz (ve aminoasitler)."},{"q":"Geri emilen su nereye geçer?","steps":[{"t":"Suyun yönü","a":"Tübülden dışarı","d":"Geri emilim sırasında su tübül içinden tübül duvarını geçerek dışarı çıkar. Dışarıda tübülleri saran kılcal damarlar bulunur. Su bu damarlara yönelir."},{"t":"Suyun varış yeri","a":"Kana (kılcal damarlara)","d":"Geri emilen su, tübülleri çevreleyen kılcal damarlara, yani kana geçer. Böylece su dolaşıma geri döner. Bu, vücudun su kaybını önler."}],"ans":"Kana (tübülleri saran kılcal damarlara)."},{"q":"Geri emilim olayında enerji harcanan kısım hangisidir?","steps":[{"t":"Geri emilim türleri","a":"Aktif ve pasif","d":"Geri emilimde bazı maddeler enerji harcanarak, bazıları enerjisiz taşınır. Su ozmozla pasif geçer. Glikoz ve iyonlar ise farklı yolla taşınır."},{"t":"Enerjili kısım","a":"Aktif taşıma","d":"Glikoz, aminoasit ve bazı iyonların geri emiliminde ATP harcayan aktif taşıma kullanılır. Bu, geri emilimin enerji gerektiren kısmıdır. Su geçişi ise genellikle pasiftir."}],"ans":"Glikoz, aminoasit ve iyonların aktif taşınması."},{"q":"Geri emilim sonucunda idrarın hacmi nasıl değişir?","steps":[{"t":"Süzüntü hacmi","a":"Başta çok","d":"Glomerulustan süzülen sıvının hacmi başlangıçta çok büyüktür. Bu sıvı tübüllere geçer. İçinde bol su bulunur."},{"t":"Geri emilimin etkisi","a":"Su geri alınır, hacim azalır","d":"Tübüllerde suyun büyük kısmı geri emilince süzüntünün hacmi belirgin biçimde azalır. Sonuçta idrar çok daha az hacimli olur. Atıklar bu az suda yoğunlaşır."}],"ans":"Su geri emildiği için idrar hacmi azalır (yoğunlaşır)."},{"q":"Geri emilim hangi nefron yapısında başlar?","steps":[{"t":"Süzüntünün yolu","a":"Kapsülden sonra tübül","d":"Süzüntü Bowman kapsülünden çıktıktan sonra ilk tübüle geçer. Geri emilim bu noktadan itibaren başlar. İlk tübül bu iş için özelleşmiştir."},{"t":"Başlangıç yapısı","a":"Proksimal tübül","d":"Geri emilim büyük ölçüde proksimal tübülde başlar ve burada en yoğundur. Glikoz, aminoasit, su ve iyonlar burada geri alınır. Sonraki bölümlerde ince ayar yapılır."}],"ans":"Proksimal tübülde."}],"zor":[{"q":"Şeker hastasında (diyabet) idrarda glikoz görülmesi geri emilim sınırıyla nasıl açıklanır?","steps":[{"t":"Kan glikozu yüksek","a":"Çok glikoz süzülür","d":"Şeker hastasında kandaki glikoz derişimi çok yüksektir. Bu nedenle glomerulusta normalden çok daha fazla glikoz süzülür. Süzüntüdeki glikoz miktarı artar."},{"t":"Geri emilim sınırı","a":"Taşıyıcılar dolar","d":"Proksimal tübüldeki glikoz taşıyıcılarının belirli bir kapasitesi (eşik değeri) vardır. Süzüntüdeki glikoz bu eşiği aşınca taşıyıcılar yetmez. Fazla glikoz geri emilemez."},{"t":"Sonuç","a":"İdrarda glikoz","d":"Geri emilemeyen fazla glikoz idrarla atılır. Bu yüzden şeker hastasının idrarında glikoz görülür. Glikoz eşiğinin aşılması bu durumu açıklar."}],"ans":"Kan glikozu eşiği aşınca taşıyıcılar doyar, fazla glikoz geri emilemez ve idrara geçer."},{"q":"Glikoz geri emiliminde bir eşik değer bulunmasının nedeni nedir?","steps":[{"t":"Taşıyıcı kavramı","a":"Glikoz taşıyıcılarla emilir","d":"Glikoz, proksimal tübülde özel taşıyıcı proteinlerle aktif olarak geri emilir. Bu taşıyıcılar glikozu kana taşır. Sayıları sınırlıdır."},{"t":"Taşıyıcının sınırı","a":"Belirli kapasite","d":"Taşıyıcı sayısı sınırlı olduğundan belirli bir hızdan fazla glikoz taşıyamazlar. Süzüntüdeki glikoz bu kapasiteyi aşınca taşıyıcılar doyar. Bu doyma noktası eşik değeri oluşturur."},{"t":"Sonuç","a":"Eşik üstü idrara geçer","d":"Glikoz eşiği, taşıyıcıların sınırlı kapasitesinden kaynaklanır. Eşik aşılırsa fazla glikoz geri emilemez ve idrara geçer. Bu yüzden glikoz geri emiliminin bir sınırı vardır."}],"ans":"Glikoz taşıyıcılarının sayısı sınırlıdır; kapasite dolunca fazlası emilemez (eşik oluşur)."},{"q":"Geri emilimin büyük kısmının proksimal tübülde olması bu bölümün yapısıyla nasıl ilişkilidir?","steps":[{"t":"Proksimal tübülün yapısı","a":"Mikrovillus ve mitokondri","d":"Proksimal tübül hücrelerinde bol mikrovillus ve çok sayıda mitokondri bulunur. Mikrovilluslar emilim yüzeyini genişletir. Mitokondriler enerji üretir."},{"t":"Yapı-işlev uyumu","a":"Yüzey ve enerji bir arada","d":"Geniş yüzey daha çok maddenin temasını, bol mitokondri ise aktif taşıma için enerjiyi sağlar. İkisi birlikte yoğun geri emilime olanak verir. Bu nedenle geri emilim burada en yüksektir."},{"t":"Sonuç","a":"Yapı geri emilime uygun","d":"Proksimal tübülün mikrovillus ve mitokondri zenginliği, onu geri emilim için ideal kılar. Bu yüzden yararlı maddelerin büyük kısmı burada geri alınır. Yapı ile işlev tam uyumludur."}],"ans":"Bol mikrovillus geniş emilim yüzeyi, bol mitokondri enerji sağlar; bu yapı yoğun geri emilime uygundur."},{"q":"Çok su içen bir kişide idrarın seyrelmesi geri emilimle nasıl açıklanır?","steps":[{"t":"Fazla su","a":"Kanda su artar","d":"Çok su içildiğinde kanın su miktarı artar ve kan seyrelir. Vücut bu fazla suyu atmak ister. Su dengesi korunmalıdır."},{"t":"Geri emilim azalır","a":"Su tutulmaz","d":"Fazla su varken böbrekler suyun geri emilimini azaltır. Böylece tübüllerdeki su kana geri alınmaz. Daha çok su idrarda kalır."},{"t":"Sonuç","a":"İdrar seyrelir","d":"Su geri emilimi azaldığında idrar bol ve seyrek (açık renkli) olur. Böylece fazla su atılır ve kan su dengesi korunur. Geri emilimin ayarlanması idrarı seyreltir."}],"ans":"Su geri emilimi azalır, fazla su idrarda kalır ve idrar seyrelir."},{"q":"Susuz kalan bir kişide idrarın koyulaşması geri emilim açısından nasıl yorumlanır?","steps":[{"t":"Su kaybı","a":"Kanda su azalır","d":"Susuz kalan kişide kanın su miktarı azalır ve kan koyulaşır. Vücut su kaybetmemek için önlem alır. Suyun korunması gerekir."},{"t":"Geri emilim artar","a":"Su geri alınır","d":"Su kıtlığında böbrekler suyun geri emilimini artırır. Tübüllerdeki suyun büyük kısmı kana döner. Geriye az su kalır."},{"t":"Sonuç","a":"İdrar koyulaşır","d":"Su geri emiliminin artmasıyla idrar az ve koyu (atıkça yoğun) olur. Böylece su kaybı en aza indirilir. Geri emilimin artması idrarı koyulaştırır."}],"ans":"Su geri emilimi artar, az ve koyu (yoğun) idrar oluşur, su kaybı azaltılır."},{"q":"Geri emilimin seçici olması (yararlıyı alıp atığı bırakması) iç denge açısından neden önemlidir?","steps":[{"t":"Seçici geri emilim","a":"Yararlı alınır","d":"Geri emilim, süzüntüdeki su, glikoz, aminoasit ve iyon gibi yararlı maddeleri kana geri alır. Atıklar ise büyük ölçüde tübülde bırakılır. Bu seçicilik korunması gerekenleri korur."},{"t":"Atığın bırakılması","a":"Atık idrarda kalır","d":"Üre gibi atıklar geri emilmeyip idrarla atılır. Böylece atıklar uzaklaştırılırken yararlı maddeler kaybedilmez. Bu denge titizlikle ayarlanır."},{"t":"Sonuç","a":"İç denge korunur","d":"Seçici geri emilim, yararlıyı tutup atığı atarak kanın bileşimini sabit tutar. Bu, iç ortam kararlılığı (homeostazi) için yaşamsaldır. Böbrek bu seçicilikle denge organı işlevi görür."}],"ans":"Yararlı maddeler korunur, atıklar atılır; böylece kanın bileşimi (iç denge) sabit kalır."},{"q":"Henle kulpunun öz bölgesini tuz bakımından derişik tutması idrarın yoğunlaştırılmasına nasıl katkı yapar?","steps":[{"t":"Henle kulpunun işi","a":"Tuz hareketi","d":"Henle kulpunun çıkan kolundan öz bölgesine tuz geçer. Bu, öz bölgesini tuz bakımından derişik (yoğun) yapar. Böylece öz bölgesi su çekici bir ortam olur."},{"t":"Suyun çekilmesi","a":"Toplama kanalından su geçer","d":"Toplama kanalı tuzca derişik öz bölgesinden geçerken, su ozmozla bu derişik ortama geçer. Böylece idrardan su geri emilir. İdrar yoğunlaşır."},{"t":"Sonuç","a":"İdrar yoğunlaştırılır","d":"Henle kulpunun yarattığı derişik öz ortamı, suyun geri emilmesini ve idrarın yoğunlaştırılmasını sağlar. Bu mekanizma su tasarrufu için önemlidir. Böylece az suyla atık atılabilir."}],"ans":"Derişik öz ortamı, toplama kanalından su çekerek idrarı yoğunlaştırır."},{"q":"180 litre süzüntüden 1-2 litre idrar oluşması suyun yüzde kaçının geri emildiğini gösterir?","steps":[{"t":"Süzüntü ve idrar","a":"180 L süzüntü, ~1-2 L idrar","d":"Günde yaklaşık 180 litre süzüntü oluşur, ancak yalnızca 1-2 litresi idrar olarak atılır. Aradaki fark geri emilen sudur. Bu büyük fark geri emilimin gücünü gösterir."},{"t":"Geri emilen oran","a":"Yaklaşık %99","d":"Süzülen suyun yaklaşık 178-179 litresi geri emilir, bu da neredeyse %99'a karşılık gelir. Yani süzülen suyun yalnızca küçük bir kısmı atılır. Geri emilim çok yüksek orandadır."},{"t":"Sonuç","a":"Suyun ~%99'u geri emilir","d":"180 litreden 1-2 litre idrar kalması, suyun yaklaşık %99'unun geri emildiğini gösterir. Bu sayede su korunur ve atıklar yoğunlaştırılır. Geri emilim su dengesinin temelidir."}],"ans":"Suyun yaklaşık %99'unun geri emildiğini gösterir."},{"q":"Glikoz geri emiliminin aktif, suyun geri emiliminin pasif olması arasındaki fark neye dayanır?","steps":[{"t":"Glikozun taşınması","a":"Derişime karşı, enerjili","d":"Glikoz çoğu zaman düşük derişimden yüksek derişime taşınır ve bu enerji gerektirir. Bu yüzden glikoz aktif taşımayla, ATP harcanarak geri emilir. Taşıyıcı proteinler kullanılır."},{"t":"Suyun taşınması","a":"Derişimi izler, enerjisiz","d":"Su ise çözünen derişimi farkını izleyerek ozmozla geçer. Tuz ve glikoz emilince oluşan derişim farkı suyu çeker. Bu geçiş için ayrı enerji gerekmez."},{"t":"Sonuç","a":"Enerji gereksinimi farkı","d":"Glikoz aktif (ATP'li), su ise pasif (ozmozla) geri emilir; fark, taşımanın derişim gradyanına göre yönüne dayanır. Glikoz gradyana karşı, su gradyanla taşınır. Bu, iki maddenin geri emilim mekanizmasını ayırır."}],"ans":"Glikoz derişime karşı (aktif, ATP'li), su ise derişimi izleyerek (pasif, ozmozla) taşınır."},{"q":"Böbreklerin günde çok büyük hacimde süzüp suyun çoğunu geri emmesi enerji açısından ne anlama gelir?","steps":[{"t":"Büyük geri emilim","a":"Çok su ve madde emilir","d":"Günde yaklaşık 180 litre süzüntüden suyun ve maddelerin büyük kısmı geri emilir. Bu, çok büyük hacimde bir geri emilim işidir. Süreklilik gerektirir."},{"t":"Aktif taşıma yükü","a":"ATP harcanır","d":"Glikoz, aminoasit ve iyonların geri emilimi aktif taşımayla yapılır ve bol ATP harcar. Büyük hacim, çok madde demektir. Bu da yüksek enerji tüketimi anlamına gelir."},{"t":"Sonuç","a":"Yüksek enerji ve oksijen","d":"Yoğun geri emilim, böbreklerin çok enerji ve dolayısıyla çok oksijen kullanmasına yol açar. Bu yüzden böbrekler bol kanlanan ve enerji harcayan organlardır. Geri emilim doğrudan enerji yüküyle ilişkilidir."}],"ans":"Yoğun aktif geri emilim çok ATP gerektirir, böbreklerin yüksek enerji ve oksijen kullanmasına yol açar."},{"q":"Geri emilim yeterince çalışmazsa kanda glikoz ve su dengesinde ne tür sorunlar görülebilir?","steps":[{"t":"Geri emilimin görevi","a":"Su ve glikozu korur","d":"Geri emilim, süzüntüdeki suyu ve glikozu kana geri alarak korur. Bu sayede kanın su ve glikoz düzeyi dengelenir. Geri emilim olmazsa bunlar kaybedilir."},{"t":"Yetersizlik etkisi","a":"İdrarla kayıp artar","d":"Geri emilim bozulursa su ve glikoz idrarla aşırı atılır. Vücut su kaybeder ve değerli glikoz boşa gider. Kan dengesi bozulur."},{"t":"Sonuç","a":"Su kaybı ve glikoz kaybı","d":"Yetersiz geri emilim, susuz kalma (dehidrasyon) ve glikoz kaybına yol açabilir. Bu da halsizlik ve denge bozukluğu doğurur. Geri emilimin sağlıklı çalışması bu sorunları önler."}],"ans":"Su ve glikoz idrarla aşırı atılır; susuz kalma ve glikoz kaybı görülebilir."},{"q":"İdrarla atılan üre miktarının yüksek, glikoz miktarının sıfıra yakın olması geri emilimin seçiciliğini nasıl gösterir?","steps":[{"t":"Üre ve glikozun durumu","a":"İkisi de süzülür","d":"Hem üre hem glikoz küçük olduğundan glomerulusta süzülür ve süzüntüye geçer. Başlangıçta ikisi de tübüldedir. Ancak akıbetleri farklıdır."},{"t":"Farklı geri emilim","a":"Glikoz alınır, üre bırakılır","d":"Glikoz yararlı olduğundan büyük ölçüde geri emilir, üre ise atık olduğundan az emilir. Bu yüzden glikoz kana döner, üre idrarda kalır. Geri emilim seçici davranır."},{"t":"Sonuç","a":"Seçicilik kanıtı","d":"İdrarda ürenin bol, glikozun yok denecek kadar az olması geri emilimin seçici olduğunu gösterir. Yararlı madde tutulur, atık atılır. Bu, böbreğin denge görevinin bir kanıtıdır."}],"ans":"Yararlı glikozun emilip atık olan ürenin bırakılması geri emilimin seçici olduğunu gösterir."},{"q":"Vücut suyu az olduğunda hipofizden salgılanan hormonun (ADH) toplama kanalında su geri emilimini artırması nasıl işler?","steps":[{"t":"Su azlığı uyarısı","a":"Kan derişir","d":"Vücut suyu azaldığında kan derişir ve bu durum algılanır. Vücut suyu korumak için bir düzenleme başlatır. Bu düzenleme hormonla yürür."},{"t":"ADH etkisi","a":"Su geçirgenliğini artırır","d":"Hipofizden salgılanan ADH, toplama kanalının suya geçirgenliğini artırır. Böylece toplama kanalından kana daha çok su geri emilir. İdrardaki su azalır."},{"t":"Sonuç","a":"Az ve koyu idrar","d":"ADH etkisiyle su geri emilimi arttığı için idrar azalır ve koyulaşır, kandaki su korunur. Bu, geri emilimin hormonla ayarlandığını gösterir. Böylece su dengesi hassas biçimde düzenlenir."}],"ans":"ADH toplama kanalının su geçirgenliğini artırır, su geri emilimi artar, idrar azalıp koyulaşır."},{"q":"Kanda tuz fazlalığı olduğunda böbreğin tuz geri emilimini azaltması iç denge için neden gereklidir?","steps":[{"t":"Tuz fazlalığı","a":"Kanda yüksek tuz","d":"Kanda tuz (iyon) derişimi arttığında iç denge bozulma riski taşır. Vücut bu fazlalığı düzeltmek ister. Fazla tuzun atılması gerekir."},{"t":"Geri emilim azalır","a":"Tuz idrara bırakılır","d":"Tuz fazlayken böbrekler tuzun geri emilimini azaltır. Böylece fazla tuz kana geri alınmaz, idrarla atılır. Kandaki tuz düzeyi düşer."},{"t":"Sonuç","a":"Tuz dengesi korunur","d":"Tuz geri emiliminin azaltılması kandaki tuz derişimini normale çeker. Bu ayarlama iç dengeyi (homeostaziyi) korur. Böbrek, geri emilimi ayarlayarak tuz dengesini sağlar."}],"ans":"Fazla tuz idrarla atılır, kandaki tuz derişimi normale döner ve iç denge korunur."},{"q":"Geri emilim ve süzme birlikte ele alındığında böbreğin neden hem süzme hem geri emilim yaptığı açıklanabilir mi?","steps":[{"t":"Süzmenin niteliği","a":"Seçici değil, geniş","d":"Glomerulustaki süzme yalnızca boyuta göre çalışır; küçük olan her şeyi (yararlı-atık) ayırt etmeden geçirir. Bu yüzden süzüntüde glikoz, su gibi yararlılar da bulunur. Süzme tek başına yararlıyı koruyamaz."},{"t":"Geri emilimin tamamlayıcılığı","a":"Yararlıyı geri alır","d":"Süzmeden sonra geri emilim devreye girerek yararlı maddeleri kana geri alır, atıkları bırakır. Böylece süzmenin ayırt etmeden geçirdiği değerli maddeler kurtarılır. Geri emilim süzmeyi tamamlar."},{"t":"Sonuç","a":"İki aşama birbirini tamamlar","d":"Böbrek önce hızlı ve geniş bir süzme yapar, sonra seçici geri emilimle yararlıyı geri alır. Bu iki aşama birlikte hem atık atımını hem madde korunmasını sağlar. Bu yüzden böbrek hem süzme hem geri emilim yapar."}],"ans":"Evet; süzme geniş ve seçicisizdir, geri emilim ise yararlıyı geri alır; ikisi birlikte hem atık atar hem değerli maddeyi korur."}]}},"sekresyon":{"lise":{"kolay":[{"q":"Tübüler salgılama (sekresyon) hangi yönde gerçekleşir?","steps":[{"t":"Kavramı tanımla","a":"Kandan tübül içine","d":"Tübüler salgılama, peritübüler kılcal damarlardaki kandan maddelerin böbrek tübülü boşluğuna (lümene) aktif olarak geçirilmesidir. Bu süreçte maddeler kan tarafından idrara doğru hareket eder, yani kandan dışarı atılmak üzere taşınır."},{"t":"Sonucu belirt","a":"Kandan idrara","d":"Bu yön, kanda fazla bulunan veya zararlı maddelerin idrara eklenmesini sağlar. Böylece süzülme sırasında atılamayan bazı maddeler de vücuttan uzaklaştırılır."}],"ans":"Kandan tübül içine (idrara doğru)"},{"q":"Tübüler salgılama ile geri emilim hangi yönde birbirine zıttır?","steps":[{"t":"İki olayı karşılaştır","a":"Geri emilim tübülden kana","d":"Geri emilimde maddeler tübül içinden (idrardan) kana geri alınır; salgılamada ise maddeler kandan tübül içine (idrara) verilir. İki olay birbirine ters yönde işler."},{"t":"Zıtlığı vurgula","a":"Salgılama kandan tübüle","d":"Geri emilim vücuda yararlı maddeleri korurken, salgılama zararlı veya fazla maddeleri atar. Bu nedenle yönleri birbirine zıttır."}],"ans":"Salgılama kandan tübüle, geri emilim tübülden kana doğrudur"},{"q":"Kandaki fazla H⁺ iyonları idrara nasıl geçer?","steps":[{"t":"Süreci belirle","a":"Tübüler salgılama","d":"Kanda biriken fazla hidrojen iyonları (H⁺) tübül hücreleri tarafından aktif taşımayla tübül boşluğuna salgılanır. Bu süreç tübüler salgılama olarak adlandırılır."},{"t":"Amacı açıkla","a":"pH dengesi için","d":"H⁺ salgılanması kanın asitliğini azaltır ve pH dengesini korur. Böylece kan fazla asitlenmekten korunur."}],"ans":"Tübüler salgılama ile"},{"q":"Tübüler salgılama böbreğin hangi bölümünde yoğun olarak gerçekleşir?","steps":[{"t":"Tübül bölümlerini hatırla","a":"Tübül boyunca","d":"Salgılama özellikle proksimal ve distal tübüllerde gerçekleşir. Tübül hücreleri kandaki maddeleri seçici olarak lümene aktarır."},{"t":"Sonucu söyle","a":"Böbrek tübüllerinde","d":"Bu bölgelerdeki hücreler aktif taşıma yapabilecek bol mitokondri içerir. Bu sayede maddeler enerji harcanarak kandan idrara geçirilebilir."}],"ans":"Böbrek tübüllerinde (özellikle distal ve proksimal)"},{"q":"Vücuttaki fazla potasyum (K⁺) idrara hangi olayla eklenir?","steps":[{"t":"Olayı tanı","a":"Salgılama","d":"Kanda fazla bulunan potasyum iyonları tübül hücreleri tarafından lümene salgılanır. Bu, geri emilimle değil tübüler salgılamayla gerçekleşir."},{"t":"Sonuca bağla","a":"İdrarla atılır","d":"Salgılanan K⁺ idrarla vücuttan uzaklaştırılır. Böylece kandaki potasyum dengesi korunur."}],"ans":"Tübüler salgılama"},{"q":"Bazı ilaçların vücuttan atılmasında tübüler salgılamanın rolü nedir?","steps":[{"t":"İlaç atılımını düşün","a":"Kandan tübüle taşınır","d":"Bazı ilaçlar ve onların artıkları tübül hücreleri tarafından kandan tübül boşluğuna aktif olarak salgılanır. Bu, sadece süzülmeyle atılamayan maddelerin de uzaklaştırılmasını sağlar."},{"t":"Sonuç","a":"İdrarla uzaklaştırılır","d":"Salgılanan ilaç artıkları idrara katılarak vücuttan atılır. Böylece kandaki ilaç düzeyi düşürülür."}],"ans":"İlaç artıklarını kandan idrara taşıyarak vücuttan atılmasını sağlar"},{"q":"Amonyak (NH₃) gibi azotlu artıkların idrara geçişinde salgılamanın katkısı var mıdır?","steps":[{"t":"Amonyağı değerlendir","a":"Salgılanabilir","d":"Tübül hücreleri amonyak üretip tübül boşluğuna salgılayabilir. Bu, kandaki asit-baz dengesinin korunmasına da yardımcı olur."},{"t":"Sonuç","a":"Evet, katkısı vardır","d":"Salgılanan amonyak H⁺ iyonlarını bağlayarak idrarla atılmasını kolaylaştırır. Bu sayede kan pH dengesi desteklenir."}],"ans":"Evet, amonyak salgılanarak idrara katılır"},{"q":"Tübüler salgılama aktif taşıma mı yoksa pasif taşıma mı gerektirir?","steps":[{"t":"Taşıma yönünü düşün","a":"Genelde derişime karşı","d":"Salgılanan maddeler çoğunlukla az yoğun ortamdan çok yoğun ortama (kandan idrara) taşınır. Bu, derişim gradyanına karşı bir harekettir."},{"t":"Enerji gereksinimi","a":"Aktif taşıma","d":"Derişim gradyanına karşı taşıma enerji (ATP) harcanmasını gerektirir. Bu nedenle salgılama büyük oranda aktif taşıma ile gerçekleşir."}],"ans":"Aktif taşıma (enerji gerektirir)"},{"q":"Tübüler salgılama kanın pH dengesini nasıl etkiler?","steps":[{"t":"H⁺ salgılanmasını düşün","a":"Asit atılır","d":"Salgılama sayesinde kandaki fazla H⁺ iyonları idrara aktarılır. Bu, kandaki asit miktarını azaltır."},{"t":"pH üzerine etkisi","a":"pH dengelenir","d":"H⁺ atılınca kanın asitliği azalır ve pH normal değere yaklaşır. Böylece kan ne fazla asidik ne de fazla bazik olur."}],"ans":"Fazla H⁺ atarak kanı asitlikten korur ve pH'ı dengeler"},{"q":"Süzülme sırasında atılamayan bir madde idrara nasıl katılabilir?","steps":[{"t":"Süzülme sınırını düşün","a":"Bazı maddeler süzülemez","d":"Bazı maddeler süzülme zarından geçemez ya da yeterince süzülemez. Bu maddeler yalnızca süzülmeyle idrara katılamaz."},{"t":"Çözüm","a":"Salgılama ile","d":"Bu durumda madde tübül hücreleri tarafından kandan tübül içine salgılanır. Böylece süzülmeyle atılamayan madde idrara katılarak atılır."}],"ans":"Tübüler salgılama ile idrara katılarak"},{"q":"Tübüler salgılamanın vücut için temel görevi nedir?","steps":[{"t":"İşlevi düşün","a":"Fazla/zararlı maddeleri atmak","d":"Salgılama, kanda biriken fazla iyonları ve zararlı artıkları idrara aktarır. Böylece bu maddeler vücuttan uzaklaştırılır."},{"t":"Genel sonuç","a":"İç denge korunur","d":"Bu olay kanın bileşimini ve pH'ını dengede tutar. Sonuçta vücudun iç dengesi (homeostazi) desteklenir."}],"ans":"Fazla ve zararlı maddeleri kandan idrara aktararak iç dengeyi korumak"},{"q":"Geri emilim olmasaydı, salgılamanın etkisi tek başına ne olurdu?","steps":[{"t":"İki olayı ayır","a":"Salgılama atar, emilim korur","d":"Salgılama maddeleri kandan idrara aktarırken, geri emilim yararlı maddeleri kana geri alır. Geri emilim olmasaydı yararlı maddeler de kaybedilirdi."},{"t":"Sonuç","a":"Sadece atılma kalırdı","d":"Bu durumda yalnızca maddelerin idrara geçişi olur, korunma olmazdı. Bu da su, glikoz gibi yararlı maddelerin kaybına yol açardı."}],"ans":"Yararlı maddeler korunamaz, sadece maddeler idrara aktarılırdı"},{"q":"Tübüler salgılama kanın temizlenmesine nasıl yardımcı olur?","steps":[{"t":"Temizleme görevini düşün","a":"Artıkları kandan alır","d":"Salgılama, kandaki zararlı artıkları ve fazla iyonları tübül içine aktarır. Bu, kanın bu maddelerden arındırılmasını sağlar."},{"t":"Sonuç","a":"Kan temizlenir","d":"Aktarılan maddeler idrarla atılır ve kan bileşimi normalleşir. Böylece kan temizlenmiş olur."}],"ans":"Zararlı ve fazla maddeleri kandan tübüle aktararak kanı temizler"},{"q":"Distal tübülde gerçekleşen salgılama hangi iyonlar için önemlidir?","steps":[{"t":"Distal tübülü düşün","a":"H⁺ ve K⁺","d":"Distal tübülde özellikle hidrojen (H⁺) ve potasyum (K⁺) iyonları salgılanır. Bu iyonların salgılanması kanın pH ve elektrolit dengesini ayarlar."},{"t":"Sonuç","a":"pH ve potasyum dengesi","d":"H⁺ salgılanması pH'ı, K⁺ salgılanması potasyum düzeyini ayarlar. Bu iyonların dengelenmesi vücut için kritik öneme sahiptir."}],"ans":"H⁺ ve K⁺ iyonları için"},{"q":"Salgılama olayı idrarın son içeriğini nasıl değiştirir?","steps":[{"t":"İdrar oluşumunu hatırla","a":"Salgılanan maddeler eklenir","d":"İdrar; süzülen, geri emilen ve salgılanan maddelerin sonucudur. Salgılama, idrara yeni maddeler ekleyerek içeriğini değiştirir."},{"t":"Sonuç","a":"İçerik zenginleşir","d":"Salgılanan H⁺, K⁺, amonyak ve ilaç artıkları idrarda son hâlde bulunur. Böylece idrar bu maddeler bakımından zenginleşir."}],"ans":"Salgılanan maddeleri ekleyerek idrarın son içeriğini değiştirir"}],"zor":[{"q":"Bir hasta sürekli asidoz (kanın asitlenmesi) yaşıyorsa böbreğin salgılama tepkisi ne olur?","steps":[{"t":"Sorunu çözümle","a":"Kanda fazla H⁺","d":"Asidoz durumunda kanda hidrojen iyonu (H⁺) derişimi artmıştır. Vücut bu fazla asidi uzaklaştırmaya çalışır."},{"t":"Böbreğin tepkisi","a":"H⁺ salgılaması artar","d":"Böbrek tübülleri kandaki fazla H⁺ iyonlarını tübül içine daha fazla salgılar. Aynı zamanda bikarbonat geri emilimini artırarak tampon kapasitesini destekler."},{"t":"Sonuç","a":"pH dengelenmeye çalışılır","d":"Artan H⁺ salgılaması idrarla asit atılmasını sağlar ve kan pH'ı yükselmeye başlar. Böylece böbrek asidozu düzeltmeye çalışır."}],"ans":"H⁺ salgılaması artar, idrarla daha çok asit atılarak kan pH'ı dengelenmeye çalışılır"},{"q":"İdrar oluşumunda \"süzülen − geri emilen + salgılanan\" eşitliğinde salgılamanın yeri nedir?","steps":[{"t":"Eşitliği çöz","a":"Üç olay birleşir","d":"İdrar miktarı ve içeriği; süzülen maddelerden geri emilenler çıkarılıp salgılananlar eklenerek bulunur. Bu eşitlik idrar oluşumunun temelini gösterir."},{"t":"Salgılamanın katkısı","a":"Ekleme yapar","d":"Salgılama, süzülmeyle yeterince atılamayan maddeleri idrara ekler. Bu nedenle eşitlikte toplama (+) terimini oluşturur."},{"t":"Sonuç","a":"İdrarı zenginleştirir","d":"Salgılama olmasaydı bazı zararlı maddeler kanda kalırdı. Bu yüzden salgılama, atılan madde miktarını süzülmenin ötesine taşır."}],"ans":"Salgılama, eşitlikte idrara eklenen (+) maddeleri temsil eder"},{"q":"Penisilin gibi bir ilacın kandan hızlı atılması neden büyük oranda salgılamaya bağlıdır?","steps":[{"t":"İlacın özelliğini düşün","a":"Süzülme yavaş kalır","d":"Penisilin gibi ilaçlar yalnızca süzülmeyle yeterince hızlı atılamaz çünkü plazma proteinlerine bağlanabilir veya süzülme oranı sınırlıdır. Bu nedenle başka bir yol gerekir."},{"t":"Salgılama devreye girer","a":"Aktif taşıma ile atılır","d":"Tübül hücreleri penisilini kandan tübül içine aktif olarak salgılar. Bu, ilacın süzülmeden bağımsız olarak hızlıca idrara geçmesini sağlar."},{"t":"Sonuç","a":"Hızlı atılım","d":"Salgılama sayesinde ilaç kısa sürede idrarla uzaklaştırılır. Bu yüzden bu ilaçların kandan temizlenmesi büyük oranda salgılamaya bağlıdır."}],"ans":"Tübüler salgılama ilacı aktif taşımayla hızla idrara aktardığı için"},{"q":"Potasyumdan zengin beslenen bir kişide böbreğin salgılama görevi nasıl değişir?","steps":[{"t":"Durumu çözümle","a":"Kanda K⁺ artar","d":"Potasyumdan zengin beslenme kandaki K⁺ derişimini yükseltir. Yüksek potasyum kalp ritmi gibi işlevleri olumsuz etkileyebilir."},{"t":"Böbreğin tepkisi","a":"K⁺ salgılaması artar","d":"Distal tübül ve toplama kanallarındaki hücreler fazla potasyumu lümene daha fazla salgılar. Bu süreç aldosteron hormonu tarafından da uyarılır."},{"t":"Sonuç","a":"K⁺ dengesi korunur","d":"Artan salgılama fazla potasyumun idrarla atılmasını sağlar. Böylece kandaki potasyum düzeyi normal sınırlarda tutulur."}],"ans":"K⁺ salgılaması artar, fazla potasyum idrarla atılarak denge korunur"},{"q":"Salgılamanın hem pH düzenlenmesi hem de zararlı madde atılımında rol oynaması neyi gösterir?","steps":[{"t":"İki işlevi karşılaştır","a":"Çok yönlü görev","d":"Salgılama hem H⁺ atarak pH ayarlar hem de ilaç artığı, fazla iyon gibi maddeleri uzaklaştırır. Bu iki işlev aynı temel mekanizmayla yürür."},{"t":"Ortak özellik","a":"Kandan idrara aktarım","d":"Her iki görevde de maddeler kandan tübül içine aktarılır. Bu, salgılamanın tek bir yön üzerinden farklı amaçlara hizmet ettiğini gösterir."},{"t":"Sonuç","a":"Çok amaçlı düzenleme","d":"Böylece salgılama hem kimyasal denge hem de detoksifikasyon sağlar. Bu da böbreğin çok yönlü düzenleyici bir organ olduğunu ortaya koyar."}],"ans":"Salgılamanın çok yönlü bir iç denge düzenleme mekanizması olduğunu gösterir"},{"q":"Bir kişide tübüler salgılama tamamen durursa kan kimyasında ne tür sorunlar beklenir?","steps":[{"t":"Salgılamanın görevini hatırla","a":"H⁺, K⁺ atılamaz","d":"Salgılama dursa kandaki fazla H⁺ ve K⁺ iyonları idrara aktarılamaz. Bu iyonlar kanda birikmeye başlar."},{"t":"Olası sonuçlar","a":"Asidoz ve hiperkalemi","d":"H⁺ birikimi kanın asitlenmesine (asidoz), K⁺ birikimi ise hiperkalemiye yol açar. Bu durumlar kalp ve sinir işlevlerini bozabilir."},{"t":"Genel etki","a":"İç denge bozulur","d":"Ayrıca ilaç artıkları ve fazla maddeler de kanda kalır. Sonuçta vücudun kimyasal iç dengesi ciddi şekilde bozulur."}],"ans":"Asidoz, hiperkalemi ve zararlı madde birikimi gibi iç denge bozuklukları beklenir"},{"q":"Geri emilim ve salgılamanın aynı tübülde ters yönlerde çalışması böbreğe nasıl bir avantaj sağlar?","steps":[{"t":"İki olayı ele al","a":"Biri korur biri atar","d":"Geri emilim yararlı maddeleri kana geri alırken, salgılama zararlı ve fazla maddeleri idrara verir. İki olay aynı yapıda ters yönlerde işler."},{"t":"Avantajı düşün","a":"Seçici düzenleme","d":"Bu sayede böbrek hangi maddeyi tutup hangisini atacağını ayrı ayrı kontrol edebilir. Yararlı maddeler korunurken zararlılar uzaklaştırılır."},{"t":"Sonuç","a":"Hassas denge","d":"Böylece kanın bileşimi çok hassas biçimde ayarlanır. Bu da iç dengenin (homeostazinin) korunmasını sağlar."}],"ans":"Yararlı maddeleri tutup zararlıları atarak kan bileşiminin hassas biçimde ayarlanmasını sağlar"},{"q":"Asetazolamid gibi H⁺ salgılamasını engelleyen bir ilaç kanın pH'ını nasıl etkiler?","steps":[{"t":"İlacın etkisini düşün","a":"H⁺ salgılanamaz","d":"Bu tür ilaçlar tübül hücrelerinde H⁺ salgılamasını azaltır. Böylece kandaki fazla asit idrara aktarılamaz."},{"t":"Sonuç","a":"Asit kanda kalır","d":"H⁺ atılamayınca kandaki asit miktarı artar. Bu da kanın pH'ının düşmesine (asidoza eğilim) yol açabilir."},{"t":"Genel etki","a":"pH düşer","d":"Aynı zamanda bikarbonat atılımı da artabilir, bu da asitlenmeyi destekler. Sonuçta kanın pH dengesi asit yönüne kayar."}],"ans":"H⁺ atılamadığı için kan asitlenmeye eğilim gösterir, pH düşer"},{"q":"Tübüler salgılamanın aktif taşıma gerektirmesi metabolik durumla nasıl bir ilişki kurar?","steps":[{"t":"Enerji gereksinimini düşün","a":"ATP gerekir","d":"Salgılama maddeleri derişim gradyanına karşı taşıdığı için ATP harcar. Bu enerjiyi tübül hücrelerinin mitokondrileri üretir."},{"t":"Metabolik bağlantı","a":"Oksijen/enerji bağımlı","d":"Hücrelerin enerji üretimi yeterli oksijen ve besine bağlıdır. Kan akışı veya oksijen azalırsa salgılama kapasitesi düşer."},{"t":"Sonuç","a":"Metabolizmaya bağımlı","d":"Bu nedenle salgılama, böbreğin metabolik aktivitesiyle doğrudan ilişkilidir. Enerji üretimi bozulursa salgılama da bozulur."}],"ans":"Aktif taşıma ATP gerektirdiği için salgılama, hücre metabolizmasına ve enerji üretimine bağımlıdır"},{"q":"Amonyak salgılanmasının asit-baz dengesindeki tampon rolü nedir?","steps":[{"t":"Amonyağın özelliğini düşün","a":"H⁺ bağlar","d":"Tübül hücrelerince salgılanan amonyak (NH₃), idrardaki H⁺ iyonlarını bağlayarak amonyum (NH₄⁺) oluşturur. Böylece serbest H⁺ azalır."},{"t":"Tampon etkisi","a":"Daha çok asit atılır","d":"H⁺ bağlandığında idrar fazla asitlenmeden daha çok hidrojen iyonu atılabilir. Bu, böbreğin asit atma kapasitesini artırır."},{"t":"Sonuç","a":"pH korunur","d":"Sonuçta kandaki asit fazlası güvenli biçimde uzaklaştırılır. Böylece amonyak, asit-baz dengesinde önemli bir tampon görevi görür."}],"ans":"Amonyak idrardaki H⁺'yi bağlayarak daha çok asit atılmasını sağlar, böylece tampon görevi görür"},{"q":"Salgılama olmadan sadece süzülme ve geri emilimle bir ilacın atılması neden yetersiz kalabilir?","steps":[{"t":"Süzülmenin sınırını düşün","a":"Bağlı ilaç süzülemez","d":"Plazma proteinlerine bağlı ilaçlar süzülme zarından geçemez. Bu nedenle yalnızca süzülmeyle bu ilaçlar idrara katılamaz."},{"t":"Geri emilimin etkisi","a":"Geri emilebilir","d":"Süzülen ilacın bir kısmı tübülde tekrar kana geri emilebilir. Bu da net atılan miktarı azaltır."},{"t":"Salgılamanın önemi","a":"Aktif atılım sağlar","d":"Salgılama, proteine bağlı ilacı bile kandan ayırıp tübüle aktif olarak aktarabilir. Bu yüzden salgılama olmadan atılım yetersiz kalır."}],"ans":"Proteine bağlı ya da geri emilebilen ilaçlar yalnızca süzülmeyle atılamadığı için salgılama gereklidir"},{"q":"Böbrek yetmezliğinde salgılama azaldığında ilaç dozlarının ayarlanması neden gerekir?","steps":[{"t":"Yetmezliği çözümle","a":"Salgılama düşer","d":"Böbrek yetmezliğinde tübüler salgılama kapasitesi azalır. Bu, salgılamayla atılan ilaçların vücuttan uzaklaştırılmasını yavaşlatır."},{"t":"İlaç birikimi","a":"Kanda birikir","d":"Atılamayan ilaç kanda birikerek normalden yüksek düzeylere ulaşabilir. Bu durum toksik (zehirleyici) etkilere yol açabilir."},{"t":"Sonuç","a":"Doz azaltılmalı","d":"Bu nedenle bu hastalarda ilaç dozları düşürülür veya aralar açılır. Böylece ilacın güvenli düzeyde kalması sağlanır."}],"ans":"Salgılama azalınca ilaçlar kanda birikip toksik etki yapabileceği için dozlar düşürülmelidir"},{"q":"Salgılama ve geri emilim birlikte düşünülürse böbrek \"akıllı bir süzgeç\" olarak neden tanımlanabilir?","steps":[{"t":"Basit süzgeci düşün","a":"Süzgeç seçemez","d":"Sıradan bir süzgeç yalnızca boyuta göre ayırır, hangi maddeyi tutup atacağını seçemez. Böbrek ise bundan çok daha fazlasını yapar."},{"t":"Böbreğin yeteneği","a":"Seçici tutar ve atar","d":"Geri emilimle yararlı maddeleri kana geri alır, salgılamayla zararlıları idrara verir. Bu seçicilik, ihtiyaca göre ayarlanabilir."},{"t":"Sonuç","a":"Akıllı süzgeç","d":"Böylece böbrek, vücudun ihtiyacına göre madde tutma ve atma kararı verir. Bu yüzden basit bir filtreden çok akıllı bir düzenleyici gibi davranır."}],"ans":"Hangi maddeyi tutup hangisini atacağını seçebildiği için akıllı bir süzgeç gibidir"},{"q":"İdrar pH'ı çok düşük (asidik) bulunan bir kişide tübüler salgılama hakkında ne söylenebilir?","steps":[{"t":"İdrar pH'ını yorumla","a":"Fazla H⁺ atılmış","d":"Asidik idrar, böbreğin idrara çok miktarda H⁺ iyonu salgıladığını gösterir. Bu, kandaki asit fazlasının atılmasının bir işaretidir."},{"t":"Olası neden","a":"Kanda asit fazlası","d":"Genellikle kanda asit fazlası olduğunda böbrek H⁺ salgılamasını artırır. Bu da idrarın asitliğini yükseltir."},{"t":"Sonuç","a":"Salgılama aktif","d":"Dolayısıyla bu kişide H⁺ salgılaması yüksek düzeyde çalışıyor demektir. Böbrek, kanı asitlikten korumak için aktif olarak çalışmaktadır."}],"ans":"Böbreğin H⁺ salgılamasının arttığı, kanı asitlikten korumak için aktif çalıştığı söylenebilir"},{"q":"Tübüler salgılama, süzülmenin \"tek başına yeterli olmadığı\" durumlarda neden kritik öneme sahiptir?","steps":[{"t":"Süzülmenin eksikliğini düşün","a":"Her madde süzülemez","d":"Süzülme bazı maddeleri (proteine bağlı veya büyük moleküller) yeterince atamaz. Ayrıca süzülen bir madde geri emilerek kana dönebilir."},{"t":"Salgılamanın katkısı","a":"Ek atılım yolu","d":"Salgılama, süzülmeyle atılamayan maddeleri kandan doğrudan tübüle aktarır. Bu, atılım için ikinci ve aktif bir yol sağlar."},{"t":"Sonuç","a":"Tam temizlik","d":"Böylece kanda kalabilecek zararlı maddeler de uzaklaştırılır. Bu yüzden salgılama, süzülmenin yetersiz kaldığı yerde kritik öneme sahiptir."}],"ans":"Süzülmeyle atılamayan maddeleri kandan aktif olarak atabildiği için kritik öneme sahiptir"}]}},"ureter":{"lise":{"kolay":[{"q":"Üreterin temel görevi nedir?","steps":[{"t":"Yapıyı tanı","a":"İdrar kanalı","d":"Üreter, böbrek ile idrar kesesi (mesane) arasında uzanan ince bir borudur. Her böbrekten bir üreter çıkar."},{"t":"Görevi belirt","a":"İdrarı taşır","d":"Üreter, böbrekte oluşan idrarı mesaneye taşır. Bu taşıma sürekli ve düzenli biçimde gerçekleşir."}],"ans":"Böbrekte oluşan idrarı mesaneye taşımak"},{"q":"Üreter idrarı hangi hareketle ilerletir?","steps":[{"t":"Hareket tipini düşün","a":"Kas hareketi","d":"Üreter duvarındaki kaslar sırayla kasılıp gevşer. Bu dalga şeklindeki harekete peristaltik hareket denir."},{"t":"Sonuç","a":"Peristaltik hareket","d":"Peristaltik dalga idrarı böbrekten mesaneye doğru iter. Böylece idrar yer çekimine bağlı kalmadan ilerleyebilir."}],"ans":"Peristaltik (dalga şeklinde kasılma) hareketle"},{"q":"Üreter duvarında bulunan hangi doku idrarın itilmesini sağlar?","steps":[{"t":"Duvar yapısını düşün","a":"Kas tabakası","d":"Üreter duvarında düz kas tabakası bulunur. Bu kaslar istem dışı çalışır."},{"t":"Sonuç","a":"Düz kas","d":"Düz kasların ritmik kasılması idrarı ileri doğru iter. Bu sayede idrar mesaneye ulaşır."}],"ans":"Düz kas tabakası"},{"q":"İnsanda kaç tane üreter bulunur?","steps":[{"t":"Böbrek sayısını hatırla","a":"İki böbrek","d":"İnsanda normalde iki böbrek vardır. Her böbrekten idrar ayrı bir kanalla taşınır."},{"t":"Sonuç","a":"İki üreter","d":"Her böbrekten bir üreter çıktığı için toplam iki üreter bulunur. Bunlar idrarı ayrı ayrı mesaneye taşır."}],"ans":"İki tane (her böbrek için bir tane)"},{"q":"Üreter hangi iki organı birbirine bağlar?","steps":[{"t":"Konumunu düşün","a":"Böbrek ve mesane arası","d":"Üreter, böbreğin idrar toplama bölgesinden başlar. Aşağı doğru uzanarak mesaneye ulaşır."},{"t":"Sonuç","a":"Böbrek ile mesane","d":"Böylece üreter böbrek ile mesane arasında bağlantı kurar. İdrar bu kanaldan geçerek mesaneye dolar."}],"ans":"Böbrek ile mesaneyi (idrar kesesini)"},{"q":"Üreterin mesaneye giriş açısı neden önemlidir?","steps":[{"t":"Giriş açısını düşün","a":"Eğik girer","d":"Üreterler mesaneye dik değil, eğik (oblik) bir açıyla girer. Bu giriş mesane duvarının içinden geçerek olur."},{"t":"Sonuç","a":"Geri kaçışı önler","d":"Mesane dolup basınç artınca bu eğik giriş kapanır. Böylece idrarın üretere geri kaçması engellenir."}],"ans":"Eğik giriş, idrarın mesaneden üretere geri kaçmasını önler"},{"q":"Böbrek taşı üreterde tıkanmaya neden olursa ne olur?","steps":[{"t":"Tıkanmayı düşün","a":"İdrar geçemez","d":"Üreterde bir taş, idrarın geçişini engelleyebilir. Bu, idrarın böbrekten mesaneye akmasını zorlaştırır."},{"t":"Sonuç","a":"İdrar birikir ve ağrı olur","d":"İdrar böbrekte birikerek basınç oluşturur ve şiddetli ağrıya (renal kolik) yol açar. Tıkanma uzun sürerse böbrek zarar görebilir."}],"ans":"İdrar akışı engellenir, idrar birikir ve şiddetli ağrı oluşur"},{"q":"Üreterdeki peristaltik hareket istemli mi yoksa istemsiz mi gerçekleşir?","steps":[{"t":"Kas tipini düşün","a":"Düz kas","d":"Üreter duvarındaki kaslar düz kastır. Düz kaslar bilincimizden bağımsız çalışır."},{"t":"Sonuç","a":"İstemsiz","d":"Bu nedenle peristaltik hareket istemsiz (otonom) olarak gerçekleşir. İdrarın taşınmasını bilinçli olarak kontrol edemeyiz."}],"ans":"İstemsiz (otonom) olarak gerçekleşir"},{"q":"Üreterin yapısı neden bir boru şeklindedir?","steps":[{"t":"İşlevini düşün","a":"Sıvı taşır","d":"Üreterin görevi idrar adı verilen sıvıyı taşımaktır. Sıvının bir noktadan diğerine akması için bir kanal gerekir."},{"t":"Sonuç","a":"Boru şekli uygun","d":"Borumsu yapı idrarın içinden akmasına imkân verir. Kaslı duvar da bu akışı yönlendirir."}],"ans":"İdrarı bir yerden diğerine taşıyabilmek için boru şeklindedir"},{"q":"Üreterler idrarı hangi yöne taşır?","steps":[{"t":"Akış yönünü düşün","a":"Yukarıdan aşağıya","d":"İdrar böbreklerde oluşur ve aşağıdaki mesaneye iletilir. Üreterler bu akışın kanalıdır."},{"t":"Sonuç","a":"Böbrekten mesaneye","d":"Peristaltik hareket idrarı böbrekten mesaneye doğru iter. Akış her zaman bu yönde gerçekleşir."}],"ans":"Böbrekten mesaneye doğru"},{"q":"Üreter taşı oluşumunda hangi maddelerin birikimi etkilidir?","steps":[{"t":"Taş içeriğini düşün","a":"Mineral kristalleri","d":"İdrardaki bazı mineraller (örneğin kalsiyum tuzları) çökelerek kristal oluşturabilir. Bu kristaller zamanla büyüyerek taşa dönüşür."},{"t":"Sonuç","a":"Mineral birikimi","d":"Birikip büyüyen kristaller üreterde taş oluşturur. Bu taşlar idrar akışını engelleyebilir."}],"ans":"İdrardaki minerallerin (kalsiyum tuzları gibi) birikip kristalleşmesi"},{"q":"Üreter olmasaydı idrar açısından ne tür bir sorun yaşanırdı?","steps":[{"t":"Görevini hatırla","a":"İdrarı taşır","d":"Üreterin görevi böbrekteki idrarı mesaneye iletmektir. Bu bağlantı olmadan idrarın gideceği yer kalmaz."},{"t":"Sonuç","a":"İdrar böbrekte birikir","d":"Üreter olmasaydı idrar böbrekte birikerek basınç yapardı. Bu da böbreğe zarar verir ve idrar atılamazdı."}],"ans":"İdrar mesaneye ulaşamaz, böbrekte birikerek zarar verirdi"},{"q":"Üreterin iç yüzeyi neden epitel dokuyla kaplıdır?","steps":[{"t":"İç yüzeyi düşün","a":"Korumalı yüzey","d":"Üreterin iç yüzeyi idrarla sürekli temas hâlindedir. İdrar içerdiği maddelerle dokuyu tahriş edebilir."},{"t":"Sonuç","a":"Epitel korur","d":"İç yüzeyi kaplayan epitel doku, duvarı idrarın etkisinden korur. Aynı zamanda esneyerek idrar geçişine uyum sağlar."}],"ans":"Duvarı idrarın etkisinden korumak ve esneklik sağlamak için"},{"q":"Üreterdeki kas tabakasının kasılması durursa ne olur?","steps":[{"t":"Kasın görevini düşün","a":"İdrarı iter","d":"Üreterdeki kaslar peristaltik hareketle idrarı iter. Bu hareket idrarın mesaneye ulaşmasını sağlar."},{"t":"Sonuç","a":"İdrar ilerleyemez","d":"Kaslar çalışmazsa idrar etkili biçimde itilemez. İdrar üreterde veya böbrekte birikmeye başlar."}],"ans":"Peristaltik hareket olmadığı için idrar ilerleyemez ve birikir"},{"q":"Üreterin mesaneye eğik girmesinin \"tek yönlü kapak\" gibi davranması ne anlama gelir?","steps":[{"t":"Tek yönlülüğü düşün","a":"Sadece içeri akış","d":"Eğik giriş, idrarın yalnızca böbrekten mesaneye akmasına izin verir. Ters yöne akış engellenir."},{"t":"Sonuç","a":"Geri kaçış olmaz","d":"Mesane dolduğunda artan basınç eğik girişi kapatır. Böylece idrar geri böbreğe kaçmaz, sistem tek yönlü çalışır."}],"ans":"İdrarın sadece tek yönde (mesaneye) akmasını sağlayıp geri kaçışı önlediği anlamına gelir"}],"zor":[{"q":"Bir hastada idrarın üreterden böbreğe geri kaçtığı (reflü) saptanırsa olası anatomik sorun nedir?","steps":[{"t":"Normal mekanizmayı hatırla","a":"Eğik giriş kapatır","d":"Normalde üreterin mesaneye eğik girişi, basınç arttığında kapanarak geri kaçışı önler. Bu, tek yönlü bir kapak gibi çalışır."},{"t":"Sorunu belirle","a":"Eğik giriş bozuk","d":"Reflü varsa üreterin mesaneye giriş açısı ya da kapanma mekanizması bozulmuş olabilir. Bu durumda mesane basıncı arttığında idrar üretere geri kaçar."},{"t":"Sonuç","a":"Geri kaçış oluşur","d":"Geri kaçan idrar böbreğe ulaşarak enfeksiyon ve böbrek hasarı riskini artırır. Bu yüzden sorun genellikle giriş açısının yetersizliğindedir."}],"ans":"Üreterin mesaneye eğik giriş açısının bozulması, kapak işlevinin yetersiz kalması"},{"q":"Üreterde tıkanan bir taşın böbreğe zarar verme mekanizmasını adım adım açıklayın.","steps":[{"t":"Tıkanmayı çözümle","a":"Akış durur","d":"Taş üreteri tıkadığında idrarın mesaneye akışı durur. İdrar taşın gerisinde, böbrek tarafında birikmeye başlar."},{"t":"Basınç artışı","a":"Böbrekte basınç","d":"Biriken idrar böbrek içinde basıncı yükseltir ve toplama yapılarını genişletir (hidronefroz). Artan basınç böbrek dokusunu sıkıştırır."},{"t":"Sonuç","a":"Doku hasarı","d":"Uzun süren basınç böbrek hücrelerinin işlevini bozar ve kalıcı hasara yol açabilir. Bu yüzden tıkanmanın hızla giderilmesi gerekir."}],"ans":"Tıkanma idrar birikimine, böbrekte basınç artışına ve sonunda doku hasarına yol açar"},{"q":"Peristaltik hareketin yer çekiminden bağımsız çalışması neden önemlidir?","steps":[{"t":"Yer çekimini düşün","a":"Tek başına yetmez","d":"Eğer idrar yalnızca yer çekimiyle aksaydı, yatar pozisyonda akış zorlaşırdı. Vücut konumu akışı engelleyebilirdi."},{"t":"Peristaltik hareketin rolü","a":"Aktif itme","d":"Peristaltik hareket kas kasılmalarıyla idrarı aktif olarak iter. Bu, vücut hangi konumda olursa olsun akışı sürdürür."},{"t":"Sonuç","a":"Sürekli akış","d":"Böylece yatarken, ayaktayken veya baş aşağıyken bile idrar taşınabilir. Bu, üriner sistemin güvenilir çalışmasını sağlar."}],"ans":"Vücut hangi konumda olursa olsun idrarın sürekli mesaneye taşınmasını sağladığı için önemlidir"},{"q":"Üreterin düz kas yapısı ile peristaltik hareket arasındaki ilişkiyi açıklayın.","steps":[{"t":"Kas tipini düşün","a":"Düz kas istemsiz","d":"Üreter duvarı istem dışı çalışan düz kastan oluşur. Bu kaslar ritmik ve otomatik kasılabilir."},{"t":"Hareketi oluştur","a":"Sıralı kasılma","d":"Düz kasların ardı ardına kasılıp gevşemesi dalga şeklinde bir hareket oluşturur. Bu dalga idrarı önündeki bölgeye doğru iter."},{"t":"Sonuç","a":"Peristaltik itme","d":"Bu sıralı kasılmalar peristaltik hareketi meydana getirir. Böylece düz kas yapısı, idrarın etkili biçimde itilmesini mümkün kılar."}],"ans":"Düz kasların sıralı, istemsiz kasılması peristaltik hareketi oluşturarak idrarı iter"},{"q":"Üreter taşı düşürürken çok su içmek neden önerilir?","steps":[{"t":"Su etkisini düşün","a":"İdrar miktarı artar","d":"Çok su içmek üretilen idrar miktarını artırır. Daha fazla idrar üreterden geçer."},{"t":"Taşa etkisi","a":"İtme gücü artar","d":"Artan idrar akışı, taşı aşağı doğru iten basıncı ve hacmi yükseltir. Bu, taşın mesaneye doğru ilerlemesine yardımcı olur."},{"t":"Sonuç","a":"Taş düşürülür","d":"Yeterli akışla küçük taşlar idrarla birlikte dışarı atılabilir. Bu yüzden bol su içmek taş düşürmeyi kolaylaştırır."}],"ans":"İdrar miktarını artırarak taşı aşağı itme gücünü yükselttiği için bol su önerilir"},{"q":"Üreterin mesane içinden eğik geçmesi, mesane dolduğunda neden daha etkili bir kapanma sağlar?","steps":[{"t":"Anatomiyi düşün","a":"Duvar içinden geçiş","d":"Üreter mesane duvarının içinden eğik bir yol izleyerek geçer. Bu, üreterin son kısmının mesane kasları arasında uzanması demektir."},{"t":"Dolu mesaneyi düşün","a":"Basınç artar","d":"Mesane dolduğunda iç basınç artar ve duvar gerilir. Artan basınç, duvar içinden geçen eğik üreter bölümünü sıkıştırarak kapatır."},{"t":"Sonuç","a":"Daha sıkı kapanma","d":"Basınç ne kadar artarsa kapanma o kadar etkili olur. Böylece mesane doluyken bile idrarın geri kaçması güçlü biçimde önlenir."}],"ans":"Artan mesane basıncı duvar içindeki eğik üreteri sıkıştırarak daha etkili bir kapanma sağlar"},{"q":"Tek bir üreteri tamamen tıkanan bir kişide o tarafın böbreği zamanla nasıl etkilenir?","steps":[{"t":"Tıkanmayı düşün","a":"İdrar atılamaz","d":"Tıkanan üreter, o böbreğin idrarını mesaneye gönderemez. İdrar böbrekte birikmeye başlar."},{"t":"Sürecin ilerleyişi","a":"Basınç ve genişleme","d":"Biriken idrar böbrek içinde basınç oluşturur ve toplama yapılarını genişletir. Bu basınç böbrek dokusunu giderek sıkıştırır."},{"t":"Sonuç","a":"İşlev kaybı","d":"Uzun sürede o böbrek işlevini yitirebilir, ancak diğer sağlam böbrek görevi üstlenir. Bu sayede kişi tek böbrekle yaşamını sürdürebilir."}],"ans":"Tıkalı taraftaki böbrek basınç altında kalıp işlevini kaybedebilir, diğer böbrek görevi üstlenir"},{"q":"Üreterdeki kas tabakasının kalınlığı ile taşıma görevi arasında nasıl bir uyum vardır?","steps":[{"t":"Görevi düşün","a":"İdrarı itmek","d":"Üreterin görevi idrarı belirli bir kuvvetle mesaneye itmektir. Bu, kasların yeterli güç üretmesini gerektirir."},{"t":"Yapısal uyum","a":"Gelişmiş kas tabakası","d":"Bu güç için üreterde belirgin bir düz kas tabakası bulunur. Kasların düzenli ve güçlü kasılması peristaltik hareketi etkili kılar."},{"t":"Sonuç","a":"Yapı-görev uyumu","d":"Böylece kas tabakasının yapısı, idrarı itme görevine uygun biçimde gelişmiştir. Yapı ile işlev birbiriyle uyumludur."}],"ans":"Gelişmiş kas tabakası, idrarı etkili biçimde itme görevine uygun olacak şekilde yapılanmıştır"},{"q":"İki üreterin ayrı ayrı çalışması böbreklerin bağımsız işlemesine nasıl katkı sağlar?","steps":[{"t":"Sistemi düşün","a":"Her böbreğe bir üreter","d":"Her böbreğin kendi üreteri vardır ve idrarını ayrı taşır. Bu, böbreklerin birbirinden bağımsız çalışmasına izin verir."},{"t":"Avantajı değerlendir","a":"Biri sorunda diğeri çalışır","d":"Bir üreter tıkansa veya bir böbrek sorun yaşasa, diğer taraf görevini sürdürebilir. Bu, sistemin güvenliğini artırır."},{"t":"Sonuç","a":"Yedekli sistem","d":"Böylece üriner sistem çift ve bağımsız çalışan bir yapıya sahip olur. Bu yedeklilik organizmanın hayatta kalma şansını yükseltir."}],"ans":"Her böbreğin kendi üreteriyle bağımsız çalışması, biri sorunda diğerinin görevini sürdürmesini sağlar"},{"q":"Yaşlılarda üreter peristaltizminin zayıflaması idrar yolu enfeksiyonu riskini neden artırabilir?","steps":[{"t":"Peristaltizmin görevini düşün","a":"İdrarı akıtır","d":"Peristaltik hareket idrarı sürekli ileri iterek akışı korur. Akan idrar, sistemi adeta yıkayarak temizler."},{"t":"Zayıflamanın etkisi","a":"İdrar durağanlaşır","d":"Peristaltizm zayıflarsa idrar üreterde yavaşlar veya durağanlaşır. Durağan idrar, bakterilerin çoğalması için uygun ortam oluşturur."},{"t":"Sonuç","a":"Enfeksiyon riski artar","d":"Bakteriler durağan idrarda kolayca çoğalıp idrar yolu enfeksiyonuna yol açabilir. Bu yüzden zayıf peristaltizm enfeksiyon riskini artırır."}],"ans":"Zayıf peristaltizm idrarın durağanlaşmasına yol açar, bu da bakteri üremesini ve enfeksiyon riskini artırır"},{"q":"Üreterin \"yalnızca taşıma\" görevi olması, idrar içeriğinin neden burada değişmediğini açıklar mı?","steps":[{"t":"Görevi düşün","a":"Sadece taşıma","d":"Üreterin tek görevi idrarı böbrekten mesaneye iletmektir. Burada süzme, geri emilim veya salgılama yapılmaz."},{"t":"İçerik üzerine etki","a":"Değişim yok","d":"Madde alışverişi olmadığı için üreterden geçen idrarın bileşimi değişmez. İdrar böbrekteki son hâliyle taşınır."},{"t":"Sonuç","a":"İçerik korunur","d":"Bu yüzden üreterin başında ve sonunda idrar aynı içeriktedir. Görevin sadece taşıma olması, içeriğin sabit kalmasını açıklar."}],"ans":"Evet, üreter yalnızca taşıma yaptığı ve madde alışverişi yapmadığı için idrar içeriği değişmez"},{"q":"Bir taşın üreterin en dar bölgelerinde sıkışması olasılığı neden daha yüksektir?","steps":[{"t":"Üreter çapını düşün","a":"Dar bölgeler var","d":"Üreterin bazı bölgeleri (örneğin mesaneye giriş bölgesi) doğal olarak daha dardır. Bu bölgelerden geçiş daha zordur."},{"t":"Taşın hareketini düşün","a":"Dar yerde takılır","d":"İlerleyen bir taş, kendi çapına yakın dar bölgelere ulaştığında geçemeyip sıkışabilir. Geniş bölgelerde ise rahatça ilerler."},{"t":"Sonuç","a":"Dar bölgede tıkanma","d":"Bu yüzden taşların en sık takıldığı yerler üreterin dar bölgeleridir. Buralarda tıkanma ve ağrı olasılığı yüksektir."}],"ans":"Taş kendi çapına yakın dar bölgelerden geçemeyip sıkıştığı için bu bölgelerde tıkanma olasılığı yüksektir"},{"q":"Üreterin geri kaçışı önlemesi, idrar yolu enfeksiyonlarının böbreğe ilerlemesini nasıl engeller?","steps":[{"t":"Geri kaçışı düşün","a":"Eğik giriş engeller","d":"Üreterin eğik girişi idrarın mesaneden böbreğe geri kaçmasını önler. Bu, tek yönlü bir akış sağlar."},{"t":"Enfeksiyona etkisi","a":"Bakteri yukarı çıkamaz","d":"Mesanede enfeksiyon olsa bile geri kaçış olmadığı için bakteri içeren idrar yukarı çıkamaz. Böylece enfeksiyonun böbreğe taşınması zorlaşır."},{"t":"Sonuç","a":"Böbrek korunur","d":"Bu mekanizma böbreği üriner enfeksiyonlardan korur. Geri kaçış mekanizması bozulursa enfeksiyon böbreğe ilerleyebilir."}],"ans":"Geri kaçışı önleyerek mesanedeki bakteri içeren idrarın böbreğe ulaşmasını engeller"},{"q":"Üreter peristaltizminin idrar miktarına göre hızlanması ne tür bir uyum sağlar?","steps":[{"t":"İdrar miktarını düşün","a":"Çok idrar gelir","d":"Böbrek çok idrar ürettiğinde üreterden geçmesi gereken hacim artar. Bu, daha hızlı taşımayı gerektirir."},{"t":"Uyumu açıkla","a":"Peristaltizm hızlanır","d":"Üreter, gelen idrar miktarına göre kasılma sıklığını artırabilir. Böylece artan idrar birikmeden mesaneye iletilir."},{"t":"Sonuç","a":"Dengeli akış","d":"Bu uyum, idrarın üreterde tıkanmadan akmasını sağlar. Sistem, üretilen idrar miktarına göre kendini ayarlar."}],"ans":"İdrar miktarına göre kasılma sıklığını artırarak idrarın birikmeden taşınmasını sağlar"},{"q":"Üreter, böbrek ve mesane arasında \"köprü\" görevi görmeseydi üriner sistemin işleyişi nasıl bozulurdu?","steps":[{"t":"Bağlantıyı düşün","a":"İki organ ayrılır","d":"Üreter, böbrek ile mesane arasındaki tek bağlantıdır. Bu köprü olmadan iki organ birbirine ulaşamaz."},{"t":"İşleyişe etkisi","a":"İdrar iletilemez","d":"Böbrekte oluşan idrar mesaneye taşınamaz ve böbrekte birikir. Mesane de depolayacak idrar bulamaz."},{"t":"Sonuç","a":"Sistem çöker","d":"İdrar atılamadığı için zararlı maddeler vücutta birikir ve böbrek zarar görür. Sonuçta tüm boşaltım sistemi işlevini yitirir."}],"ans":"İdrar böbrekten mesaneye iletilemez, böbrekte birikir ve tüm boşaltım sistemi işlevini yitirir"}]}}};
